package auth

import (
	"errors"
	"net/http"
	"strings"

	"github.com/golang-jwt/jwt/v4"
)

type ErrorKind string

const (
	ErrorKindMissingToken           ErrorKind = "missing_token"
	ErrorKindInvalidToken           ErrorKind = "invalid_token"
	ErrorKindUserNotFound           ErrorKind = "user_not_found"
	ErrorKindUserLoadFailed         ErrorKind = "user_load_failed"
	ErrorKindPasswordChangeRequired ErrorKind = "password_change_required"
	ErrorKindAdminRequired          ErrorKind = "admin_required"
	ErrorKindServiceUnavailable     ErrorKind = "service_unavailable"
)

type AuthError struct {
	Kind    ErrorKind
	Message string
}

func (e *AuthError) Error() string {
	if e == nil {
		return ""
	}
	return e.Message
}

func newAuthError(kind ErrorKind) *AuthError {
	return &AuthError{Kind: kind, Message: kind.defaultMessage()}
}

func (k ErrorKind) defaultMessage() string {
	switch k {
	case ErrorKindMissingToken:
		return "Authorization header is required"
	case ErrorKindInvalidToken:
		return "Invalid token"
	case ErrorKindUserNotFound:
		return "User not found"
	case ErrorKindUserLoadFailed:
		return "Failed to load user"
	case ErrorKindPasswordChangeRequired:
		return "Password change required"
	case ErrorKindAdminRequired:
		return "admin privileges required"
	case ErrorKindServiceUnavailable:
		return "authentication service unavailable"
	default:
		return "authentication failed"
	}
}

// ExtractTokenFromHeader extracts the JWT token from the Authorization header of the request
func extractTokenFromHeader(r *http.Request) (string, error) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return "", errors.New("authorization header is required")
	}
	return strings.TrimPrefix(authHeader, "Bearer "), nil
}

// ParseToken parses the JWT token and returns the claims
func parseToken(tokenString string, keyFunc jwt.Keyfunc) (*jwt.Token, error) {
	return jwt.ParseWithClaims(tokenString, &UserClaims{}, keyFunc)
}

package adminhandlers

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"socialpredict/handlers"
	"socialpredict/handlers/authhttp"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
	configsvc "socialpredict/internal/service/config"
	"socialpredict/logger"
	"socialpredict/security"
	"strings"
)

type adminUserCreator interface {
	CreateAdminManagedUser(ctx context.Context, req dusers.AdminManagedUserCreateRequest) (*dusers.AdminManagedUserCreateResult, error)
}

func AddUserHandler(userCreator adminUserCreator, configService configsvc.Service, auth authsvc.Authenticator, securityService *security.SecurityService) func(http.ResponseWriter, *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		responseData, handlerErr := processAddUser(r, userCreator, configService, auth, securityService)
		if handlerErr != nil {
			_ = handlers.WriteFailure(w, handlerErr.statusCode, handlerErr.reason)
			logAddUserFailure(handlerErr)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(responseData)
		if username, ok := responseData["username"].(string); ok {
			logger.LogInfo("AddUser", "ProcessAddUser", "Created user "+username)
		}
	}
}

type handlerError struct {
	message    string
	statusCode int
	logErr     error
	reason     handlers.FailureReason
}

func processAddUser(r *http.Request, userCreator adminUserCreator, configService configsvc.Service, auth authsvc.Authenticator, securityService *security.SecurityService) (map[string]interface{}, *handlerError) {
	req, decodeErr := decodeAddUserRequest(r)
	if decodeErr != nil {
		return nil, &handlerError{
			message:    decodeErr.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     decodeErr,
			reason:     handlers.ReasonInvalidRequest,
		}
	}

	if securityService == nil {
		return nil, &handlerError{message: "security service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}

	if err := validateAddUserUsername(securityService, req.Username); err != nil {
		return nil, &handlerError{
			message:    "Invalid username: " + err.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     err,
			reason:     handlers.ReasonValidationFailed,
		}
	}
	req.Username, _ = securityService.Sanitizer.SanitizeUsername(req.Username)

	if userCreator == nil {
		return nil, &handlerError{message: "user service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}

	if auth == nil {
		return nil, &handlerError{message: "authentication service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}
	if _, authErr := auth.RequireAdmin(r); authErr != nil {
		return nil, &handlerError{
			message:    authErr.Message,
			statusCode: authhttp.StatusCode(authErr),
			logErr:     errors.New(authErr.Message),
			reason:     authhttp.FailureReason(authErr),
		}
	}

	if configService == nil {
		return nil, &handlerError{message: "configuration service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}

	appConfig := configService.Current()
	result, err := userCreator.CreateAdminManagedUser(r.Context(), dusers.AdminManagedUserCreateRequest{
		Username:              req.Username,
		InitialAccountBalance: appConfig.Economics.User.InitialAccountBalance,
	})
	if err != nil {
		return nil, addUserCreateError(err)
	}

	responseData := map[string]interface{}{
		"message":  "User created successfully",
		"username": result.Username,
		"password": result.Password,
		"usertype": result.UserType,
	}
	return responseData, nil
}

type addUserRequest struct {
	Username string `json:"username" validate:"required,min=3,max=30,username"`
}

func decodeAddUserRequest(r *http.Request) (addUserRequest, error) {
	var req addUserRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return addUserRequest{}, fmt.Errorf("Error decoding request body")
	}
	return req, nil
}

func validateAddUserUsername(securityService *security.SecurityService, username string) error {
	if err := securityService.Validator.ValidateStruct(addUserRequest{Username: username}); err != nil {
		return err
	}
	_, err := securityService.Sanitizer.SanitizeUsername(username)
	return err
}

func addUserCreateError(err error) *handlerError {
	if errors.Is(err, dusers.ErrUserAlreadyExists) {
		validationErr := fmt.Errorf("username, display name, email, or API key already in use")
		return &handlerError{
			message:    validationErr.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     validationErr,
			reason:     handlers.ReasonValidationFailed,
		}
	}

	return &handlerError{
		message:    "Failed to create user",
		statusCode: http.StatusInternalServerError,
		logErr:     err,
		reason:     handlers.ReasonInternalError,
	}
}

func logAddUserFailure(handlerErr *handlerError) {
	if handlerErr == nil || handlerErr.logErr == nil {
		return
	}

	if handlerErr.statusCode >= http.StatusInternalServerError {
		logger.LogError("AddUser", "ProcessAddUser", handlerErr.logErr)
		return
	}

	message := strings.TrimSpace(handlerErr.message)
	if message == "" {
		message = handlerErr.logErr.Error()
	}
	logger.LogWarn("AddUser", "ProcessAddUser", message)
}

package auth

import (
	"net/http"
	"strings"

	dusers "socialpredict/internal/domain/users"
)

// Authenticator exposes the authentication operations used by HTTP handlers.
type Authenticator interface {
	CurrentUser(r *http.Request) (*dusers.User, *AuthError)
	RequireUser(r *http.Request) (*dusers.User, *AuthError)
	RequireAdmin(r *http.Request) (*dusers.User, *AuthError)
}

// AuthService provides a façade over the authentication helpers so callers can
// depend on a single injected object rather than package-level functions.
type AuthService struct {
	users         dusers.ServiceInterface
	jwtSigningKey []byte
}

// NewAuthService constructs a façade that uses the provided users service for
// token validation and password-change enforcement.
func NewAuthService(users dusers.ServiceInterface, jwtSigningKey ...[]byte) *AuthService {
	var key []byte
	if len(jwtSigningKey) > 0 && len(jwtSigningKey[0]) > 0 {
		key = append([]byte(nil), jwtSigningKey[0]...)
	} else {
		key = currentJWTSigningKey()
	}
	return &AuthService{users: users, jwtSigningKey: key}
}

// CurrentUser returns the authenticated user, ensuring any password-change
// requirements are enforced.
func (a *AuthService) CurrentUser(r *http.Request) (*dusers.User, *AuthError) {
	return ValidateUserAndEnforcePasswordChangeGetUserWithSigningKey(r, a.users, a.jwtSigningKey)
}

// RequireUser resolves the authenticated user without checking the
// must-change-password flag.
func (a *AuthService) RequireUser(r *http.Request) (*dusers.User, *AuthError) {
	return ValidateTokenAndGetUserWithSigningKey(r, a.users, a.jwtSigningKey)
}

// RequireAdmin ensures the current user is authenticated and has admin privileges.
func (a *AuthService) RequireAdmin(r *http.Request) (*dusers.User, *AuthError) {
	user, err := a.CurrentUser(r)
	if err != nil {
		return nil, err
	}

	if strings.ToUpper(user.UserType) != "ADMIN" {
		return nil, newAuthError(ErrorKindAdminRequired)
	}

	return user, nil
}

package auth

import (
	"errors"
	"net/http"
)

// ValidateAdminToken uses the provided authenticator to ensure the request is
// made by an admin user. Prefer calling auth.RequireAdmin directly; this helper
// exists for backwards compatibility with legacy call sites.
func ValidateAdminToken(r *http.Request, auth Authenticator) error {
	if auth == nil {
		return errors.New("authenticator is required")
	}

	user, authErr := auth.RequireAdmin(r)
	if authErr != nil {
		return errors.New(authErr.Message)
	}

	// Extra guard: RequireAdmin already checks admin, but ensure status handling.
	if user == nil {
		return errors.New("unauthorized")
	}

	return nil
}

