func AddUserHandler(userCreator adminUserCreator, configService configsvc.Service, auth authhttp.AdminAuthenticator, securityService *security.SecurityService) func(http.ResponseWriter, *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		responseData, handlerErr := processAddUser(r, userCreator, configService, auth, securityService)
		if handlerErr != nil {
			_ = handlers.WriteFailure(w, handlerErr.statusCode, handlerErr.reason)
			logAddUserFailure(handlerErr)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(responseData)
		if username, ok := responseData["username"].(string); ok {
			logger.LogInfo("AddUser", "ProcessAddUser", "Created user "+username)
		}
	}
}

